SELECT * FROM ( SELECT ROWNUM AS rn, x.* FROM ( SELECT c.coupon_id AS couponId, pts.partner_id AS partnerId, pts.partner_name AS partnerName, c.coupon_name AS couponName, c.discount_amount AS discountAmount, c.discount_type AS discountType, c.max_discount_amount AS maxDiscountAmount, c.min_order_amount AS minOrderAmount, c.platform_share AS platformShare, c.partner_share AS partnerShare, c.valid_from AS validFrom, c.valid_until AS validUntil, CASE WHEN c.status = 'INACTIVE' THEN 'INACTIVE' WHEN SYSDATE < c.valid_from THEN 'SCHEDULED' WHEN SYSDATE > c.valid_until THEN 'EXPIRED' ELSE 'ACTIVE' END AS status, c.created_at AS createdAt, c.issue_condition_type AS issueConditionType, c.issue_condition_value AS issueConditionValue, (SELECT COUNT(*) FROM member_coupon mc WHERE mc.coupon_id = c.coupon_id) AS issuedCount FROM coupon c LEFT JOIN (
