SELECT * FROM ( SELECT ROWNUM AS rn, t.* FROM ( SELECT mc.member_coupon_id AS memberCouponId, mc.coupon_id AS couponId, c.coupon_name AS couponName, pts.partner_id AS partnerId, pts.partner_name AS partnerName, mc.member_id AS memberId, m.login_id AS loginId, c.discount_type AS discountType, c.discount_amount AS discountAmount, mc.issued_at AS issuedAt, c.valid_until AS validUntil, mc.expired_at AS expiredAt, mc.status AS status FROM member_coupon mc JOIN coupon c ON mc.coupon_id = c.coupon_id JOIN member1 m ON mc.member_id = m.member_id LEFT JOIN (
) pts ON pts.coupon_id = c.coupon_id
AND mc.status = #{status}
AND c.coupon_name LIKE '%' || #{couponKeyword} || '%'
AND m.login_id LIKE '%' || #{memberKeyword} || '%'
ORDER BY mc.issued_at DESC ) t WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

